spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var barWidth = 200;
    var barHeight = 22;
    var startX = (W - barWidth) / 2;

    var centerY1 = H / 2 - 38;
    var centerY2 = H / 2 - 3;
    var centerY3 = H / 2 + 32;

    // Progress stages
    // 0 - 2s: empty bars
    // 2s - 4.5s: fill bar 1 (1/2)
    // 4.5s - 7s: fill bar 2 (2/4)
    // 7s - 9.5s: fill bar 3 (4/8)
    // 9.5s - 12s: show dotted line and text

    var f1 = 0;
    var f2 = 0;
    var f3 = 0;

    if (progress >= 0.16) f1 = Math.min(1, (progress - 0.16) / 0.10);
    if (progress >= 0.38) f2 = Math.min(1, (progress - 0.38) / 0.10);
    if (progress >= 0.58) f3 = Math.min(1, (progress - 0.58) / 0.10);

    if (progress >= 0.79) {
      f1 = 1; f2 = 1; f3 = 1;
    }

    function drawBar(y, divisions, fillRatio, color) {
      // Draw segments
      var segWidth = barWidth / divisions;
      var segmentsToFill = Math.round(divisions / 2) * fillRatio;

      for (var i = 0; i < divisions; i++) {
        var rx = startX + i * segWidth;
        ctx.beginPath();
        ctx.rect(rx, y - barHeight / 2, segWidth, barHeight);

        if (i < segmentsToFill) {
          ctx.fillStyle = color;
          ctx.fill();
          ctx.strokeStyle = '#3B82F6';
        } else {
          ctx.fillStyle = '#1F2937';
          ctx.fill();
          ctx.strokeStyle = '#374151';
        }
        ctx.lineWidth = 1.5;
        ctx.stroke();
      }
    }

    // Draw the three bars
    drawBar(centerY1, 2, f1, '#3B82F6');
    drawBar(centerY2, 4, f2, '#10B981');
    drawBar(centerY3, 8, f3, '#F59E0B');

    // Text labels for each bar
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '11px -apple-system, sans-serif';
    ctx.textAlign = 'right';
    ctx.fillText('1/2 =', startX - 10, centerY1 + 4);
    ctx.fillText('2/4 =', startX - 10, centerY2 + 4);
    ctx.fillText('4/8 =', startX - 10, centerY3 + 4);

    ctx.textAlign = 'left';
    ctx.fillText('1 of 2 parts', startX + barWidth + 10, centerY1 + 4);
    ctx.fillText('2 of 4 parts', startX + barWidth + 10, centerY2 + 4);
    ctx.fillText('4 of 8 parts', startX + barWidth + 10, centerY3 + 4);

    // Dotted vertical line when comparison is active
    if (progress >= 0.75) {
      ctx.beginPath();
      ctx.setLineDash([4, 4]);
      ctx.moveTo(W / 2, centerY1 - 20); 
      ctx.lineTo(W / 2, centerY3 + 20);
      ctx.strokeStyle = '#EF4444'; // Red alignment line
      ctx.lineWidth = 2;
      ctx.stroke();
      ctx.setLineDash([]); // Reset dash

      // Equivalence formula text
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('1/2  =  2/4  =  4/8', W / 2, H - 32);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('The shaded length is identical in all bars!', W / 2, H - 12);
    } else {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('Dividing Wholes into More Parts', W / 2, H - 32);
    }
  }
};
